import{_ as a,o as s,c as l,ag as t}from"./chunks/framework.Cqf6AMW8.js";const k=JSON.parse('{"title":"CSS 基础盒子模型","description":"CSS 盒子模型相关知识，包括盒子组成、内边距、外边距、边框等。","frontmatter":{"title":"CSS 基础盒子模型","description":"CSS 盒子模型相关知识，包括盒子组成、内边距、外边距、边框等。","date":"2026-04-21T00:00:00.000Z","tags":["CSS","盒子模型"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/css/CSS-基础-3-盒子模型.md","filePath":"docs/frontend/css/CSS-基础-3-盒子模型.md","lastUpdated":1776715536000}'),r={name:"docs/frontend/css/CSS-基础-3-盒子模型.md"};function n(o,i,e,p,h,d){return s(),l("div",null,[...i[0]||(i[0]=[t('<p>#CSS</p><p>======================================================</p><h2 id="_1-盒子模型基础" tabindex="-1">1. 盒子模型基础 <a class="header-anchor" href="#_1-盒子模型基础" aria-label="Permalink to &quot;1. 盒子模型基础&quot;">​</a></h2><h3 id="_1-1-基本说明" tabindex="-1">1.1 基本说明 <a class="header-anchor" href="#_1-1-基本说明" aria-label="Permalink to &quot;1.1 基本说明&quot;">​</a></h3><ul><li><p>使用类选择器画盒子：三属性</p></li><li><p>实际书写中，几乎都是盒子，&lt;<strong>div</strong>&gt;大量使用</p></li></ul><h3 id="_1-2-常用属性" tabindex="-1">1.2 常用属性 <a class="header-anchor" href="#_1-2-常用属性" aria-label="Permalink to &quot;1.2 常用属性&quot;">​</a></h3><ul><li><p><strong>width</strong>：宽度</p></li><li><p><strong>height</strong>：高度</p></li><li><p><strong>background-color</strong>：背景色</p></li></ul><p>======================================================</p><h2 id="_2-盒子模型组成" tabindex="-1">2. 盒子模型组成 <a class="header-anchor" href="#_2-盒子模型组成" aria-label="Permalink to &quot;2. 盒子模型组成&quot;">​</a></h2><h3 id="_2-1-内容区" tabindex="-1">2.1 内容区 <a class="header-anchor" href="#_2-1-内容区" aria-label="Permalink to &quot;2.1 内容区&quot;">​</a></h3><ul><li><p><strong>width</strong>：内容区的宽度</p></li><li><p><strong>height</strong>：内容区的高度</p></li></ul><h3 id="_2-2-内边距" tabindex="-1">2.2 内边距 <a class="header-anchor" href="#_2-2-内边距" aria-label="Permalink to &quot;2.2 内边距&quot;">​</a></h3><ul><li><p><strong>padding-top</strong>：上内边距</p></li><li><p><strong>padding-right</strong>：右内边距</p></li><li><p><strong>padding-bottom</strong>：下内边距</p></li><li><p><strong>padding-left</strong>：左内边距</p></li><li><p><strong>padding</strong>：简写属性，可同时设置四个方向的内边距</p></li></ul><h3 id="_2-3-外边距" tabindex="-1">2.3 外边距 <a class="header-anchor" href="#_2-3-外边距" aria-label="Permalink to &quot;2.3 外边距&quot;">​</a></h3><ul><li><p><strong>margin-top</strong>：上外边距</p></li><li><p><strong>margin-right</strong>：右外边距</p></li><li><p><strong>margin-bottom</strong>：下外边距</p></li><li><p><strong>margin-left</strong>：左外边距</p></li><li><p><strong>margin</strong>：简写属性，可同时设置四个方向的外边距</p></li></ul><h3 id="_2-4-边框" tabindex="-1">2.4 边框 <a class="header-anchor" href="#_2-4-边框" aria-label="Permalink to &quot;2.4 边框&quot;">​</a></h3><ul><li><p><strong>border-width</strong>：边框宽度</p></li><li><p><strong>border-style</strong>：边框样式，如solid、dashed、dotted等</p></li><li><p><strong>border-color</strong>：边框颜色</p></li><li><p><strong>border</strong>：简写属性，可同时设置宽度、样式和颜色</p></li><li><p><strong>方向边框</strong>：border-top、border-right、border-bottom、border-left</p></li></ul><h3 id="_2-5-box-sizing属性" tabindex="-1">2.5 box-sizing属性 <a class="header-anchor" href="#_2-5-box-sizing属性" aria-label="Permalink to &quot;2.5 box-sizing属性&quot;">​</a></h3><ul><li><strong>content-box</strong>：标准盒子模型（默认值）</li></ul><p>======================================================</p><h2 id="_3-盒子装饰" tabindex="-1">3. 盒子装饰 <a class="header-anchor" href="#_3-盒子装饰" aria-label="Permalink to &quot;3. 盒子装饰&quot;">​</a></h2><h3 id="_3-1-圆角" tabindex="-1">3.1 圆角 <a class="header-anchor" href="#_3-1-圆角" aria-label="Permalink to &quot;3.1 圆角&quot;">​</a></h3><ul><li><p><strong>border-radius</strong>：设置元素的圆角</p></li><li><p><strong>取值</strong>：像素值、百分比</p></li><li><p><strong>设置圆形</strong>：<code>border-radius: 50%;</code></p></li></ul><h3 id="_3-2-盒子阴影" tabindex="-1">3.2 盒子阴影 <a class="header-anchor" href="#_3-2-盒子阴影" aria-label="Permalink to &quot;3.2 盒子阴影&quot;">​</a></h3><ul><li><p><strong>box-shadow</strong>：设置元素的阴影效果</p></li><li><p><strong>语法</strong>：<code>box-shadow: h-shadow v-shadow blur spread color inset</code></p></li><li><p><strong>参数</strong>：</p><ul><li>h-shadow：水平阴影位置</li><li>v-shadow：垂直阴影位置</li><li>blur：模糊距离</li><li>spread：阴影大小</li><li>color：阴影颜色</li><li>inset：内阴影（可选）</li></ul></li></ul><p>======================================================</p><h2 id="_4-外边距问题" tabindex="-1">4. 外边距问题 <a class="header-anchor" href="#_4-外边距问题" aria-label="Permalink to &quot;4. 外边距问题&quot;">​</a></h2><h3 id="_4-1-外边距合并" tabindex="-1">4.1 外边距合并 <a class="header-anchor" href="#_4-1-外边距合并" aria-label="Permalink to &quot;4.1 外边距合并&quot;">​</a></h3><ul><li><p><strong>场景</strong>：垂直排列的兄弟元素，上下 margin 会合并</p></li><li><p><strong>现象</strong>：取两个 margin 中的较大值生效</p></li></ul><h3 id="_4-2-外边距塌陷" tabindex="-1">4.2 外边距塌陷 <a class="header-anchor" href="#_4-2-外边距塌陷" aria-label="Permalink to &quot;4.2 外边距塌陷&quot;">​</a></h3><ul><li><p><strong>场景</strong>：父子级的标签，子级的添加上外边距会产生塌陷问题</p></li><li><p><strong>现象</strong>：导致父级一起向下移动</p></li><li><p><strong>解决方法</strong>：</p><ul><li>1.取消子级margin，父级设置padding</li><li>2.父级设置 overflow: hidden</li><li>3.父级设置 border-top</li></ul></li></ul><p>======================================================</p><h2 id="_5-内容溢出overflow属性" tabindex="-1">5. 内容溢出overflow属性 <a class="header-anchor" href="#_5-内容溢出overflow属性" aria-label="Permalink to &quot;5. 内容溢出overflow属性&quot;">​</a></h2><h3 id="_5-1-基本属性" tabindex="-1">5.1 基本属性 <a class="header-anchor" href="#_5-1-基本属性" aria-label="Permalink to &quot;5.1 基本属性&quot;">​</a></h3><ul><li><p><strong>overflow</strong>：控制内容溢出时的显示方式</p></li><li><p><strong>overflow-x</strong>：控制水平方向的内容溢出</p></li><li><p><strong>overflow-y</strong>：控制垂直方向的内容溢出</p></li></ul><h3 id="_5-2-常见取值" tabindex="-1">5.2 常见取值 <a class="header-anchor" href="#_5-2-常见取值" aria-label="Permalink to &quot;5.2 常见取值&quot;">​</a></h3><ul><li><p><strong>visible</strong>：默认值，内容溢出时会显示在元素外部</p></li><li><p><strong>hidden</strong>：内容溢出时会被裁剪，不显示溢出部分</p></li><li><p><strong>scroll</strong>：无论内容是否溢出，都会显示滚动条</p></li><li><p><strong>auto</strong>：只有当内容溢出时，才会显示滚动条</p></li></ul><p>======================================================</p><h2 id="_6-span增加上下间距" tabindex="-1">6. span增加上下间距 <a class="header-anchor" href="#_6-span增加上下间距" aria-label="Permalink to &quot;6. span增加上下间距&quot;">​</a></h2><ul><li><p><strong>方法1</strong>：将span转换为块级元素或行内块元素</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">display</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">inline-block</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">margin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span></code></pre></div></li><li><p><strong>方法2</strong>：使用padding代替margin</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">padding</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span></code></pre></div></li><li><p><strong>方法3</strong>：使用line-height控制行高</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">line-height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">40</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span></code></pre></div></li></ul><p>======================================================</p>',41)])])}const c=a(r,[["render",n]]);export{k as __pageData,c as default};
